+  (200, 'https://deliveroo.co.uk/orders/222/status');
+`
+	cmd := exec.Command("sqlite3", dbPath, sql) //nolint:gosec
+	if out, err := cmd.CombinedOutput(); err != nil {
+		t.Fatalf("sqlite init: %v out=%s", err, out)
+	}
